//! Language-agnostic IR helpers shared by per-language extractors.
//!
//! Per-language extractors (typescript.rs, python.rs, future go/rust/java)
//! convert their tree-sitter nodes into the orchestration IR — a small
//! `serde_json::Value` shape — and then delegate the IR → property-map step
//! to this module. That step is the same across languages: walk the IR JSON,
//! emit `expr` / `bind` / `callee` / `args` keys, and let downstream walkers
//! (notably gnexec) evaluate without re-parsing source.
//!
//! Helpers are `pub(crate)` so other crates don't depend on this surface.
//!
//! ## Contract notes
//!
//! `build_return_props` is intentionally narrow — it emits only `expr`.
//! Python's earlier (newer) implementation also surfaced `callee`/`args` for
//! `return foo(...)` shape, but the TypeScript implementation (shipped first
//! and the reference contract per AGENTS.md guidance) does not. Per-language
//! extractors that want the broader behavior layer it on at the call site,
//! e.g. via `ir_call_callee_args`.

use std::collections::BTreeMap;

use serde_json::Value;

use crate::cfg::FunctionParam;

/// Readability alias — the IR is a `serde_json::Value`.
pub(crate) use serde_json::Value as Ir;

/// Build orchestration-only properties for an `Entry` (function-declaration)
/// node. Emits `param_names` (a JSON-encoded array of parameter names) so
/// downstream walkers (notably gnexec) can bind call arguments by position
/// without re-running a language-specific regex over the source.
///
/// Empty `params` slice returns an empty map; callers should still go through
/// `add_node_with_props` for consistency.
///
/// `param_defaults` is emitted as a JSON object mapping name -> raw source of
/// the default expression when at least one parameter has a `default_value`.
/// Languages without defaults (Go, Rust, Java prior to optional patterns) will
/// simply not emit this key.
pub(crate) fn build_entry_props(params: &[FunctionParam]) -> BTreeMap<String, String> {
    let mut props = BTreeMap::new();
    let names: Vec<String> = params.iter().map(|p| p.name.clone()).collect();
    if let Ok(json) = serde_json::to_string(&names) {
        props.insert("param_names".to_string(), json);
    }
    let defaults: BTreeMap<String, String> = params
        .iter()
        .filter_map(|p| {
            p.default_value
                .as_ref()
                .map(|d| (p.name.clone(), d.clone()))
        })
        .collect();
    if !defaults.is_empty() {
        if let Ok(json) = serde_json::to_string(&defaults) {
            props.insert("param_defaults".to_string(), json);
        }
    }
    props
}

/// If the IR is `{kind:"ident", name:...}`, return the name.
pub(crate) fn ir_as_simple_ident(ir: &Value) -> Option<String> {
    if ir.get("kind").and_then(|v| v.as_str()) == Some("ident") {
        ir.get("name").and_then(|v| v.as_str()).map(str::to_string)
    } else {
        None
    }
}

/// If the IR is a call (or an `await`/`yield` wrapping a call), return a
/// reference to the inner call IR `{kind:"call", callee, args}`.
pub(crate) fn ir_as_call(ir: &Value) -> Option<&Value> {
    let kind = ir.get("kind").and_then(|v| v.as_str());
    if kind == Some("await") || kind == Some("yield") {
        let inner = ir.get("arg")?;
        return ir_as_call(inner);
    }
    if kind == Some("call") {
        Some(ir)
    } else {
        None
    }
}

/// Convenience: combine `ir_as_call` + `ir_callee_to_string` + args extract.
/// Returns `(callee_string, args_array)` if the IR resolves to a call whose
/// callee can be flattened to a dotted string.
pub(crate) fn ir_call_callee_args(ir: &Value) -> Option<(String, Vec<Value>)> {
    let call = ir_as_call(ir)?;
    let callee = call.get("callee")?;
    let callee_str = ir_callee_to_string(callee)?;
    let args = call
        .get("args")
        .and_then(|v| v.as_array())
        .cloned()
        .unwrap_or_default();
    Some((callee_str, args))
}

/// Convert a callee IR value to its dotted-string form, e.g. `Math.max` or
/// `os.path.join`. Returns `None` for callees that cannot be flattened (e.g.
/// dynamic indexing, computed members).
pub(crate) fn ir_callee_to_string(v: &Value) -> Option<String> {
    match v {
        Value::String(s) => Some(s.clone()),
        _ => match v.get("kind").and_then(|k| k.as_str()) {
            Some("ident") => v.get("name").and_then(|n| n.as_str()).map(str::to_string),
            Some("member") => {
                let obj = v.get("obj")?;
                let prop = v.get("prop").and_then(|p| p.as_str())?;
                let obj_str = ir_callee_to_string(obj)?;
                Some(format!("{}.{}", obj_str, prop))
            }
            _ => None,
        },
    }
}

/// True when `s` is a plain `[A-Za-z_][A-Za-z0-9_]*` field name — the shape
/// property-carried walkers (gg-walker-wasm, gnexec) accept as a `member`
/// IR `prop`. Used by per-language extractors to decide whether a literal
/// string key (`input["name"]`, `input.get("name")`) canonicalizes to
/// `member` IR or must stay language-shaped (`index` / `call`).
pub(crate) fn is_plain_field_name(s: &str) -> bool {
    let mut chars = s.chars();
    match chars.next() {
        Some(c) if c.is_ascii_alphabetic() || c == '_' => {}
        _ => return false,
    }
    chars.all(|c| c.is_ascii_alphanumeric() || c == '_')
}

/// Canonicalize a string-concatenation chain (`"hello:" + name`,
/// `"a" + x + "b"`) into `template` IR — the same shape TypeScript template
/// literals lower to — so downstream walkers evaluate concatenation without
/// language-specific `+` semantics.
///
/// `lhs`/`rhs` are the already-lowered operand IRs (left-associative chains
/// arrive with an already-templated lhs). Returns `Some(template)` only when
/// the chain PROVABLY concatenates strings: at least one operand is a string
/// literal or an existing template. Anything else (numeric arithmetic,
/// ident-only `a + b`) returns `None` and the caller keeps the plain
/// `binary` IR — additive, fail-closed canonicalization.
pub(crate) fn concat_chain_to_template(lhs: &Value, rhs: &Value) -> Option<Value> {
    fn is_stringy(v: &Value) -> bool {
        match v.get("kind").and_then(Value::as_str) {
            Some("template") => true,
            Some("literal") => v.get("value").is_some_and(Value::is_string),
            _ => false,
        }
    }
    if !is_stringy(lhs) && !is_stringy(rhs) {
        return None;
    }
    let mut parts: Vec<Value> = Vec::new();
    for operand in [lhs, rhs] {
        match operand.get("kind").and_then(Value::as_str) {
            Some("template") => {
                if let Some(inner) = operand.get("parts").and_then(Value::as_array) {
                    parts.extend(inner.iter().cloned());
                }
            }
            Some("literal") if operand.get("value").is_some_and(Value::is_string) => {
                let s = operand
                    .get("value")
                    .and_then(Value::as_str)
                    .unwrap_or_default();
                if !s.is_empty() {
                    parts.push(serde_json::json!({ "kind": "text", "s": s }));
                }
            }
            _ => parts.push(serde_json::json!({ "kind": "expr", "e": operand })),
        }
    }
    Some(serde_json::json!({ "kind": "template", "parts": parts }))
}

/// Build orchestration-only properties for a return statement, given the
/// already-converted IR of the returned expression.
///
/// Narrow contract (TS reference): emits only `expr`. Per-language extractors
/// that want `callee`/`args` for `return foo(...)` shape should layer it on at
/// the call site via `ir_call_callee_args`.
pub(crate) fn build_return_props(ir: Ir) -> BTreeMap<String, String> {
    let mut props = BTreeMap::new();
    if let Ok(s) = serde_json::to_string(&ir) {
        props.insert("expr".to_string(), s);
    }
    props
}

/// Build orchestration-only properties for a bare expression statement, given
/// the already-converted IR of the expression.
///
/// Emits `expr` always; emits `callee`/`args` if either:
///   * `callee_hint` / `args_hint` are explicitly supplied (caller already
///     knows the call shape — e.g. an assignment RHS), or
///   * `ir_call_callee_args` resolves the IR to a call.
pub(crate) fn build_expression_statement_props(
    ir: Ir,
    callee_hint: Option<&str>,
    args_hint: Option<&Value>,
) -> BTreeMap<String, String> {
    let mut props = BTreeMap::new();
    if let Ok(s) = serde_json::to_string(&ir) {
        props.insert("expr".to_string(), s);
    }

    if let (Some(callee), Some(args)) = (callee_hint, args_hint) {
        props.insert("callee".to_string(), callee.to_string());
        if let Ok(args_json) = serde_json::to_string(args) {
            props.insert("args".to_string(), args_json);
        }
    } else if let Some((callee, args)) = ir_call_callee_args(&ir) {
        props.insert("callee".to_string(), callee);
        if let Ok(args_json) = serde_json::to_string(&args) {
            props.insert("args".to_string(), args_json);
        }
    }

    props
}

/// Build orchestration-only properties for a `let foo = expr` style
/// declaration. `bind` is the bound variable name (already extracted by the
/// caller); `ir` is the initializer expression IR.
///
/// Emits `bind`, `expr`, and (if the IR is a call) `callee`/`args`.
pub(crate) fn build_declaration_props(bind: &str, ir: Ir) -> BTreeMap<String, String> {
    let mut props = BTreeMap::new();
    props.insert("bind".to_string(), bind.to_string());
    if let Ok(s) = serde_json::to_string(&ir) {
        props.insert("expr".to_string(), s);
    }
    if let Some((callee, args)) = ir_call_callee_args(&ir) {
        props.insert("callee".to_string(), callee);
        if let Ok(args_json) = serde_json::to_string(&args) {
            props.insert("args".to_string(), args_json);
        }
    }
    props
}

#[cfg(test)]
mod tests {
    use super::*;
    use serde_json::json;

    #[test]
    fn ir_as_simple_ident_extracts_name() {
        let v = json!({ "kind": "ident", "name": "foo" });
        assert_eq!(ir_as_simple_ident(&v), Some("foo".to_string()));
        let v2 = json!({ "kind": "literal", "value": 1 });
        assert_eq!(ir_as_simple_ident(&v2), None);
    }

    #[test]
    fn ir_callee_flattens_member_chain() {
        let v = json!({
            "kind": "member",
            "obj": { "kind": "ident", "name": "Math" },
            "prop": "max"
        });
        assert_eq!(ir_callee_to_string(&v), Some("Math.max".to_string()));
    }

    #[test]
    fn ir_as_call_unwraps_await() {
        let inner = json!({ "kind": "call", "callee": "foo", "args": [] });
        let outer = json!({ "kind": "await", "arg": inner.clone() });
        assert_eq!(ir_as_call(&outer), Some(&inner));
    }

    #[test]
    fn build_return_props_emits_expr_only() {
        let ir = json!({ "kind": "literal", "value": 42 });
        let props = build_return_props(ir);
        assert!(props.contains_key("expr"));
        assert!(!props.contains_key("callee"));
    }

    #[test]
    fn plain_field_names_accept_idents_and_reject_paths() {
        assert!(is_plain_field_name("name"));
        assert!(is_plain_field_name("_x9"));
        assert!(!is_plain_field_name(""));
        assert!(!is_plain_field_name("9lives"));
        assert!(!is_plain_field_name("a.b"));
        assert!(!is_plain_field_name("a-b"));
    }

    #[test]
    fn concat_chain_lowers_string_literal_plus_ident_to_template() {
        let lhs = json!({ "kind": "literal", "value": "hello:" });
        let rhs = json!({ "kind": "ident", "name": "name" });
        let tpl = concat_chain_to_template(&lhs, &rhs).expect("lowers");
        assert_eq!(
            tpl,
            json!({ "kind": "template", "parts": [
                { "kind": "text", "s": "hello:" },
                { "kind": "expr", "e": { "kind": "ident", "name": "name" } },
            ]})
        );
    }

    #[test]
    fn concat_chain_splices_nested_templates_left_associatively() {
        let lhs = json!({ "kind": "template", "parts": [
            { "kind": "text", "s": "a" },
            { "kind": "expr", "e": { "kind": "ident", "name": "x" } },
        ]});
        let rhs = json!({ "kind": "literal", "value": "b" });
        let tpl = concat_chain_to_template(&lhs, &rhs).expect("lowers");
        assert_eq!(
            tpl["parts"],
            json!([
                { "kind": "text", "s": "a" },
                { "kind": "expr", "e": { "kind": "ident", "name": "x" } },
                { "kind": "text", "s": "b" },
            ])
        );
    }

    #[test]
    fn concat_chain_refuses_non_string_chains() {
        // `a + b` and `1 + 2` stay binary IR — no proof of string concat.
        let a = json!({ "kind": "ident", "name": "a" });
        let b = json!({ "kind": "ident", "name": "b" });
        assert!(concat_chain_to_template(&a, &b).is_none());
        let one = json!({ "kind": "literal", "value": 1 });
        let two = json!({ "kind": "literal", "value": 2 });
        assert!(concat_chain_to_template(&one, &two).is_none());
    }

    #[test]
    fn build_declaration_props_includes_callee_when_call() {
        let ir = json!({
            "kind": "call",
            "callee": "fib",
            "args": [{ "kind": "literal", "value": 10 }]
        });
        let props = build_declaration_props("x", ir);
        assert_eq!(props.get("bind").map(String::as_str), Some("x"));
        assert_eq!(props.get("callee").map(String::as_str), Some("fib"));
        assert!(props.contains_key("args"));
    }
}
